#!/usr/bin/env node
/**
 * Vendor the canonical Creative Commons legal code into the repo.
 *
 * The LICENSE file Alembic writes into a published course repo must contain the
 * license's *verbatim* legal text — that is what GitHub's license detector
 * matches, and it is what makes the repository self-describing to anyone who
 * finds it without Alembic. Legal text must never be paraphrased, summarized, or
 * reconstructed from memory, so it is fetched from creativecommons.org and
 * committed, rather than typed.
 *
 * Run:  node scripts/fetch-licenses.mjs
 * Then: commit the generated file. Re-run only to refresh (the CC 4.0 texts are
 * versioned and do not change; a diff here should be treated as suspicious).
 *
 * Output: packages/package-ops/src/license-texts.generated.ts
 */

import { createHash } from "node:crypto";
import { execFileSync } from "node:child_process";
import { writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

/**
 * Node's global fetch is unavailable in some sandboxed/CI environments that
 * nonetheless allow curl. Try fetch, fall back to curl, and fail loudly if
 * neither can reach the canonical text — we must never silently vendor nothing.
 */
async function download(url) {
  try {
    const res = await fetch(url, { redirect: "follow" });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.text();
  } catch (err) {
    process.stdout.write("(fetch blocked, using curl) ");
    return execFileSync("curl", ["-sSL", "--fail", url], { encoding: "utf8", maxBuffer: 1 << 24 });
  }
}

const HERE = dirname(fileURLToPath(import.meta.url));
const OUT = join(HERE, "..", "packages", "package-ops", "src", "license-texts.generated.ts");

/** license id -> canonical legal-code URL (plain text). */
const SOURCES = {
  "CC-BY-4.0": "https://creativecommons.org/licenses/by/4.0/legalcode.txt",
  "CC-BY-SA-4.0": "https://creativecommons.org/licenses/by-sa/4.0/legalcode.txt",
  "CC-BY-NC-4.0": "https://creativecommons.org/licenses/by-nc/4.0/legalcode.txt",
  "CC-BY-NC-SA-4.0": "https://creativecommons.org/licenses/by-nc-sa/4.0/legalcode.txt",
  "CC0-1.0": "https://creativecommons.org/publicdomain/zero/1.0/legalcode.txt",
};

/** A fetched text that doesn't look like the license it claims to be is a bug. */
const EXPECT_FIRST_LINE = {
  "CC-BY-4.0": "Attribution 4.0 International",
  "CC-BY-SA-4.0": "Attribution-ShareAlike 4.0 International",
  "CC-BY-NC-4.0": "Attribution-NonCommercial 4.0 International",
  "CC-BY-NC-SA-4.0": "Attribution-NonCommercial-ShareAlike 4.0 International",
  "CC0-1.0": "Creative Commons Legal Code",
};

function asTemplateLiteral(text) {
  // Backticks and `${` would break out of the template literal.
  return text.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${");
}

const entries = [];
for (const [id, url] of Object.entries(SOURCES)) {
  process.stdout.write(`fetching ${id} … `);
  const raw = await download(url);
  const text = raw.replace(/\r\n/g, "\n").trimEnd() + "\n";

  const first = text.split("\n", 1)[0].trim();
  if (first !== EXPECT_FIRST_LINE[id]) {
    throw new Error(`${id}: unexpected first line ${JSON.stringify(first)} — refusing to vendor`);
  }
  if (text.length < 5000) throw new Error(`${id}: suspiciously short (${text.length} bytes)`);

  const sha = createHash("sha256").update(text).digest("hex").slice(0, 16);
  console.log(`${text.length} bytes, sha256:${sha}`);
  entries.push({ id, url, sha, text });
}

const body = `// GENERATED by scripts/fetch-licenses.mjs — DO NOT EDIT BY HAND.
//
// Verbatim legal code, fetched from creativecommons.org. Alembic writes this
// text, unmodified, as the LICENSE file of a published course repository:
// GitHub's license detector matches the verbatim text, and a repository that
// carries the real terms is self-describing to anyone who finds it outside
// Alembic. Never paraphrase or hand-edit these strings.
//
// The attribution/copyright line is deliberately NOT prepended here: a preamble
// can defeat GitHub's detector. Attribution is carried by the published page's
// rights notice, the JSON-LD, and CITATION.cff.

import type { License } from "@alembic/package-contract";

export interface VendoredLicense {
  /** Canonical source of the text. */
  readonly url: string;
  /** sha256 (first 16 hex chars) of the vendored text, for drift detection. */
  readonly sha256: string;
  /** The verbatim legal code. */
  readonly text: string;
}

// Partial: only the OPEN licenses have vendored legal text. An all-rights-reserved
// package has no open deed — license-file.ts writes a copyright notice for it directly.
export const LICENSE_TEXTS: Partial<Record<License, VendoredLicense>> = {
${entries
  .map(
    (e) => `  ${JSON.stringify(e.id)}: {
    url: ${JSON.stringify(e.url)},
    sha256: ${JSON.stringify(e.sha)},
    text: \`${asTemplateLiteral(e.text)}\`,
  },`,
  )
  .join("\n")}
};
`;

await writeFile(OUT, body, "utf8");
console.log(`\nwrote ${OUT} (${body.length} bytes)`);
